mapper.select:
SELECT 
    sr.*,
    s.supplier_name,
    s.supplier_code
FROM supplier_reconciliation sr
LEFT JOIN supplier s ON sr.supplier_id = s.supplier_id


        AND sr.supplier_id = #{supplierId}


        AND sr.status = #{status}


        AND sr.create_time >= #{startDate}


        AND sr.create_time <= #{endDate}


ORDER BY sr.create_time DESC
